def faces(pairing, left=True):
    coords, edges, rot, edge_type=build_planar(pairing)
    visited=set()
    face_cycles=[]
    for eid0,(u0,v0,t0) in enumerate(edges):
        for a0,b0 in [(u0,v0),(v0,u0)]:
            dart=(eid0,a0,b0)
            if dart in visited: continue
            cyc=[]; cur=dart
            while cur not in visited:
                visited.add(cur); cyc.append(cur)
                ceid,a,b=cur
                lst=rot[b]
                idx=lst.index((ceid,a))
                next_idx=(idx-1)%len(lst) if left else (idx+1)%len(lst)
                ne,w=lst[next_idx]
                cur=(ne,b,w)
            face_cycles.append(cyc)
    return face_cycles, edges, edge_type

def face_M_components(pairing, use_left=True):
    fcs, edges, edge_type=faces(pairing, use_left)
    comps=[]
    for cyc in fcs:
        m=len(cyc)
        types=[edge_type[d[0]] for d in cyc]
        if all(t=='M' for t in types):
            comps.append((None,None,cyc))
            continue
        for idx,d in enumerate(cyc):
            if types[idx]=='M' and types[(idx-1)%m]=='B':
                j=idx
                run=[]
                while types[j%m]=='M':
                    run.append(cyc[j%m]); j+=1
                start=run[0][1]; end=run[-1][2]
                comps.append((start,end,run))
    return comps

def admissible(pairing, labels, verbose=False):
    comps=face_M_components(pairing, True)
    for s,e,run in comps:
        if s is None or e is None or s[0]!='e' or e[0]!='e':
            if verbose: print("bad endpoints",s,e,run)
            return False
        i=s[1]; j=e[1]
        if labels[i] != inv_label(labels[j]):
            if verbose: print("label fail",i,j,labels[i],labels[j], "pair",pairing)
            return False
    return True

