def gf2_rank(mat):
    # mat as list of ints bitsets or numpy uint8
    A=[int(row) for row in mat if row]
    rank=0
    while A:
        # find pivot highest bit
        p=max(A)
        hb=p.bit_length()-1
        # take row with hb
        idx=next(i for i,x in enumerate(A) if x.bit_length()-1==hb)
        pivot=A.pop(idx)
        rank+=1
        new=[]
        for x in A:
            if (x>>hb)&1:
                x ^= pivot
            if x: new.append(x)
        A=new
    return rank

def betti_mod2(cells):
    # cells list all cells closed under faces; boundary maps over F2 ignoring signs: k-cell boundary = sum of all codim1 facets (2 per crossing)
    bydim=collections.defaultdict(list)
    for c in cells:
        bydim[cell_dim(c)].append(c)
    maxd=max(bydim) if bydim else -1
    idx={d:{c:i for i,c in enumerate(bydim[d])} for d in bydim}
    ranks={}
    for d in range(1,maxd+1):
        rows=[0]*len(bydim[d-1]) # matrix rows? rank of columns as bitsets columns length rows
        colbits=[]
        for c in bydim[d]:
            bit=0
            P=list(c)
            for i,j in combinations(range(len(P)),2):
                if interleave(P[i],P[j]):
                    for q in resolve_pairing(c,(i,j)):
                        bit ^= (1<<idx[d-1][q]) # mod2: if duplicate cancels
            colbits.append(bit)
        ranks[d]=gf2_rank(colbits)
    betti={}
    for d in range(0,maxd+1):
        nd=len(bydim[d])
        rank_boundary_d = ranks.get(d,0) # im from C_d to C_{d-1}
        rank_boundary_next = ranks.get(d+1,0)
        betti[d] = nd - rank_boundary_d - rank_boundary_next
    return betti, {d:len(bydim[d]) for d in bydim}, ranks

